class Solution:
    def minSubArrayLen(self, target: int, nums: List[int]) -> int:
        n, ans, s, l = len(nums), float('inf'), 0, 0
        for r in range(n):
            s += nums[r]
            while s >= target:
                ans = min(ans, r - l + 1)
                s -= nums[l]
                l += 1
        return 0 if ans == float('inf') else ans

